// MARK: - Password Hashing Service

class PasswordHashingService {
    
    static let shared = PasswordHashingService()
    
    private let saltLength = 32
    private let hashIterations: UInt32 = 10000
    private let derivedKeyLength = 64
    
    private init() {}
    
    // Generate a cryptographically secure random salt
    func generateSalt() -> Data {
        var salt = Data(count: saltLength)
        salt.withUnsafeMutableBytes { buffer in
            guard let baseAddress = buffer.baseAddress else { return }
            _ = SecRandomCopyBytes(kSecRandomDefault, saltLength, baseAddress)
        }
        return salt
    }
    
    // PBKDF2-HMAC-SHA512 hashing using CommonCrypto (available iOS 2+)
    func hashPassword(_ password: String, salt: Data) -> Data? {
        guard let passwordData = password.data(using: .utf8) else { return nil }
        
        var derivedKey = Data(count: derivedKeyLength)
        
        let result = derivedKey.withUnsafeMutableBytes { derivedKeyBytes in
            salt.withUnsafeBytes { saltBytes in
                CCKeyDerivationPBKDF(
                    CCPBKDFAlgorithm(kCCPBKDF2),
                    password,
                    passwordData.count,
                    saltBytes.bindMemory(to: UInt8.self).baseAddress!,
                    salt.count,
                    CCPseudoRandomAlgorithm(kCCPRFHmacAlgSHA512),
                    hashIterations,
                    derivedKeyBytes.bindMemory(to: UInt8.self).baseAddress!,
                    derivedKeyLength
                )
            }
        }
        
        guard result == kCCSuccess else { return nil }
        return derivedKey
    }
    
    // SHA-256 fast hash for non-critical operations
    func sha256(_ input: String) -> String? {
        guard let data = input.data(using: .utf8) else { return nil }
        
        var hash = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        data.withUnsafeBytes { buffer in
            _ = CC_SHA256(buffer.baseAddress!, CC_LONG(data.count), &hash)
        }
        
        return hash.map { String(format: "%02x", $0) }.joined()
    }
    
    // Constant-time comparison to prevent timing attacks
    func secureCompare(_ a: Data, _ b: Data) -> Bool {
        guard a.count == b.count else { return false }
        
        var result: UInt8 = 0
        for i in 0..<a.count {
            result |= a[i] ^ b[i]
        }
        return result == 0
    }
}

// MARK: - Secure Storage Service (Keychain-based)

class SecureStorageService {
    
    static let shared = SecureStorageService()
    
    private let serviceName = "com.passwordvault.storage"
    
    private init() {}
    
    func save(data: Data, for account: String, key: String) -> Bool {
        let tag = "\(account)_\(key)"
        
        // Delete existing item first
        delete(for: account, key: key)
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: tag,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        let status = SecItemAdd(query as CFDictionary, nil)
        return status == errSecSuccess
    }
    
    func load(for account: String, key: String) -> Data? {
        let tag = "\(account)_\(key)"
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: tag,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess else { return nil }
        return result as? Data
    }
    
    func delete(for account: String, key: String) {
        let tag = "\(account)_\(key)"
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: tag
        ]
        
        SecItemDelete(query as CFDictionary)
    }
    
    func deleteAll(for account: String) {
        delete(for: account, key: "hash")
        delete(for: account, key: "salt")
    }
    
    // Get all stored accounts
    func getAllAccounts() -> [String] {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecReturnAttributes as String: true,
            kSecMatchLimit as String: kSecMatchLimitAll
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let items = result as? [[String: Any]] else {
            return []
        }
        
        var accounts = Set<String>()
        for item in items {
            if let account = item[kSecAttrAccount as String] as? String {
                // Extract the account name (before the underscore separator)
                let components = account.components(separatedBy: "_")
                if let first = components.first {
                    accounts.insert(first)
                }
            }
        }
        
        return Array(accounts).sorted()
    }
}

// MARK: - Password Manager

class PasswordManager {
    
    static let shared = PasswordManager()
    
    private let hashingService = PasswordHashingService.shared
    private let storageService = SecureStorageService.shared
    
    private init() {}
    
    // Register a new password for a username
    func registerPassword(_ password: String, for username: String) -> Result<Void, PasswordError> {
        // Validate password strength
        if let validationError = validatePasswordStrength(password) {
            return .failure(validationError)
        }
        
        let normalizedUsername = username.lowercased().trimmingCharacters(in: .whitespacesAndNewlines)
        
        // Generate salt
        let salt = hashingService.generateSalt()
        
        // Hash the password
        guard let hash = hashingService.hashPassword(password, salt: salt) else {
            return .failure(.hashingFailed)
        }
        
        // Store salt and hash
        let saltSaved = storageService.save(data: salt, for: normalizedUsername, key: "salt")
        let hashSaved = storageService.save(data: hash, for: normalizedUsername, key: "hash")
        
        guard saltSaved && hashSaved else {
            storageService.deleteAll(for: normalizedUsername)
            return .failure(.storageFailed)
        }
        
        // Store creation timestamp
        let timestamp = "\(Date().timeIntervalSince1970)".data(using: .utf8)!
        _ = storageService.save(data: timestamp, for: normalizedUsername, key: "created")
        
        return .success(())
    }
    
    // Verify a password offline
    func verifyPassword(_ password: String, for username: String) -> Result<Bool, PasswordError> {
        let normalizedUsername = username.lowercased().trimmingCharacters(in: .whitespacesAndNewlines)
        
        // Retrieve stored salt and hash
        guard let storedSalt = storageService.load(for: normalizedUsername, key: "salt") else {
            return .failure(.userNotFound)
        }
        
        guard let storedHash = storageService.load(for: normalizedUsername, key: "hash") else {
            return .failure(.userNotFound)
        }
        
        // Hash the provided password with the stored salt
        guard let computedHash = hashingService.hashPassword(password, salt: storedSalt) else {
            return .failure(.hashingFailed)
        }
        
        // Constant-time comparison
        let isValid = hashingService.secureCompare(storedHash, computedHash)
        
        // Update last verification timestamp
        if isValid {
            let timestamp = "\(Date().timeIntervalSince1970)".data(using: .utf8)!
            _ = storageService.save(data: timestamp, for: normalizedUsername, key: "lastVerified")
        }
        
        return .success(isValid)
    }
    
    // Change password
    func changePassword(for username: String, oldPassword: String, newPassword: String) -> Result<Void, PasswordError> {
        // First verify old password
        switch verifyPassword(oldPassword, for: username) {
        case .success(let isValid):
            guard isValid else { return .failure(.incorrectPassword) }
        case .failure(let error):
            return .failure(error)
        }
        
        // Register new password
        return registerPassword(newPassword, for: username)
    }
    
    // Delete a user's credentials
    func deleteCredentials(for username: String) {
        let normalizedUsername = username.lowercased().trimmingCharacters(in: .whitespacesAndNewlines)
        storageService.deleteAll(for: normalizedUsername)
        storageService.delete(for: normalizedUsername, key: "created")
        storageService.delete(for: normalizedUsername, key: "lastVerified")
    }
    
    // Check if user exists
    func userExists(_ username: String) -> Bool {
        let normalizedUsername = username.lowercased().trimmingCharacters(in: .whitespacesAndNewlines)
        return storageService.load(for: normalizedUsername, key: "hash") != nil
    }
    
    // Get all registered usernames
    func getAllUsers() -> [String] {
        return storageService.getAllAccounts()
    }
    
    // Validate password strength
    private func validatePasswordStrength(_ password: String) -> PasswordError? {
        if password.count < 8 {
            return .passwordTooShort
        }
        
        let hasUppercase = password.range(of: "[A-Z]", options: .regularExpression) != nil
        let hasLowercase = password.range(of: "[a-z]", options: .regularExpression) != nil
        let hasDigit = password.range(of: "[0-9]", options: .regularExpression) != nil
        let hasSpecial = password.range(of: "[^A-Za-z0-9]", options: .regularExpression) != nil
        
        if !(hasUppercase && hasLowercase && hasDigit) {
            return .passwordTooWeak
        }
        
        // Calculate strength score
        var score = 0
        if hasUppercase { score += 1 }
        if hasLowercase { score += 1 }
        if hasDigit { score += 1 }
        if hasSpecial { score += 1 }
        if password.count >= 12 { score += 1 }
        
        if score < 3 {
            return .passwordTooWeak
        }
        
        return nil
    }
}

// MARK: - Error Types

enum PasswordError: Error, LocalizedError {
    case passwordTooShort
    case passwordTooWeak
    case hashingFailed
    case storageFailed
    case userNotFound
    case incorrectPassword
    case userAlreadyExists
    
    var errorDescription: String? {
        switch self {
        case .passwordTooShort:
            return "Password must be at least 8 characters long."
        case .passwordTooWeak:
            return "Password must contain uppercase, lowercase, and numeric characters."
        case .hashingFailed:
            return "Failed to hash the password."
        case .storageFailed:
            return "Failed to save credentials securely."
        case .userNotFound:
            return "No credentials found for this user."
        case .incorrectPassword:
            return "The password is incorrect."
        case .userAlreadyExists:
            return "A user with this name already exists."
        }
    }
}

