        textField.isSecureTextEntry.toggle()
        sender.setTitle(textField.isSecureTextEntry ? "👁" : "🔒", for: .normal)
    }
    
    @objc private func modeChanged() {
        updateUIForMode()
        clearFields()
    }
    
    private func updateUIForMode() {
        let mode = segmentedControl.selectedSegmentIndex
        
        switch mode {
        case 0: // Register
            passwordTextField.placeholder = "Password"
            newPasswordTextField.isHidden = true
            confirmPasswordTextField.isHidden = true
            actionButton.setTitle("Register", for: .normal)
            actionButton.backgroundColor = UIColor(red: 0.0, green: 0.48, blue: 1.0, alpha: 1.0)
            
        case 1: // Verify
            passwordTextField.placeholder = "Password"
            newPasswordTextField.isHidden = true
            confirmPasswordTextField.isHidden = true
            actionButton.setTitle("Verify Password", for: .normal)
            actionButton.backgroundColor = UIColor(red: 0.2, green: 0.7, blue: 0.3, alpha: 1.0)
            
        case 2: // Change
            passwordTextField.placeholder = "Current Password"
            newPasswordTextField.isHidden = false
            confirmPasswordTextField.isHidden = false
            actionButton.setTitle("Change Password", for: .normal)
            actionButton.backgroundColor = UIColor(red: 0.9, green: 0.5, blue: 0.0, alpha: 1.0)
            
        default:
            break
        }
    }
    
    @objc private func actionButtonTapped() {
        dismissKeyboard()
        
        guard let username = usernameTextField.text, !username.isEmpty else {
            showStatus("Please enter a username.", isError: true)
            return
        }
        
        guard let password = passwordTextField.text, !password.isEmpty else {
            showStatus("Please enter a password.", isError: true)
            return
        }
        
        let mode = segmentedControl.selectedSegmentIndex
        
        // Disable button and show activity
        actionButton.isEnabled = false
        let originalTitle = actionButton.title(for: .normal)
        actionButton.setTitle("Processing...", for: .normal)
        
        DispatchQueue.global(qos: .userInitiated).async { [weak self] in
            guard let self = self else { return }
            
            var resultMessage = ""
            var isError = false
            
            switch mode {
            case 0: // Register
                if self.passwordManager.userExists(username) {
                    resultMessage = "User '\(username)' already exists. Use 'Change' to update password."
                    isError = true
                } else {
                    switch self.passwordManager.registerPassword(password, for: username) {
                    case .success:
                        resultMessage = "✅ User '\(username)' registered successfully!\nPassword hashed with PBKDF2-HMAC-SHA512."
                    case .failure(let error):
                        resultMessage = "❌ \(error.localizedDescription)"
                        isError = true
                    }
                }
                
            case 1: // Verify
                switch self.passwordManager.verifyPassword(password, for: username) {
                case .success(let isValid):
                    if isValid {
                        resultMessage = "✅ Password verified successfully!\nOffline authentication passed."
                    } else {
                        resultMessage = "❌ Incorrect password."
                        isError = true
                    }
                case .failure(let error):
                    resultMessage = "❌ \(error.localizedDescription)"
                    isError = true
                }
                
            case 2: // Change
                guard let newPassword = self.newPasswordTextField.text, !newPassword.isEmpty else {
                    resultMessage = "Please enter a new password."
                    isError = true
                    break
                }
                guard let confirmPassword = self.confirmPasswordTextField.text, confirmPassword == newPassword else {
                    resultMessage = "New passwords do not match."
                    isError = true
                    break
                }
                
                switch self.passwordManager.changePassword(for: username, oldPassword: password, newPassword: newPassword) {
                case .success:
                    resultMessage = "✅ Password changed successfully for '\(username)'!"
                case .failure(let error):
                    resultMessage = "❌ \(error.localizedDescription)"
                    isError = true
                }
                
            default:
                break
            }
            
            DispatchQueue.main.async {
                self.showStatus(resultMessage, isError: isError)
                self.actionButton.isEnabled = true
                self.actionButton.setTitle(originalTitle, for: .normal)
                self.refreshUsersList()
                
                if !isError {
                    self.clearFields()
                }
            }
        }
    }
    
    private func showStatus(_ message: String, isError: Bool) {
        statusLabel.text = message
        statusLabel.textColor = isError ? .red : UIColor(red: 0.0, green: 0.6, blue: 0.0, alpha: 1.0)
        
        // Animate
        statusLabel.alpha = 0
        UIView.animate(withDuration: 0.3) {
            self.statusLabel.alpha = 1.0
        }
    }
    
    private func clearFields() {
        passwordTextField.text = ""
        newPasswordTextField.text = ""
        confirmPasswordTextField.text = ""
        statusLabel.text = ""
    }
    
    private func refreshUsersList() {
        let users = passwordManager.getAllUsers()
        if users.isEmpty {
            usersListLabel.text = "📋 Registered Users: None"
        } else {
            let userList = users.map { "• \($0)" }.joined(separator: "\n")
            usersListLabel.text = "📋 Registered Users (\(users.count)):\n\(userList)"
        }
    }
    
    @objc private func dismissKeyboard() {
        view.endEditing(true)
    }
}

